<section class="hm-blog-sec">
<div class="container">
<h2 class="text-heading">Blog Posts</h2>
<div class="home-posts-list">
        <?php
        $args = array(
            'post_type' => 'post',
            'posts_per_page' => 3,
            'orderby' => 'date',
            'order' => 'DESC',      
        );
         
        $loop = new WP_Query($args);
         
        if ($loop->have_posts()) :
            while ($loop->have_posts()) : $loop->the_post();
        ?>

    <div class="hm-blog-itm">
    
        <div class="hm-blog-img">
             <a href="<?php the_permalink(); ?>"><img src="<?php echo get_stylesheet_directory_uri(); ?>/images/default-post.webp" alt="Home Default Post" width="" height=""></a>
        </div>
        <div class="hm-blog-cnt">
             <h3><a href="<?php the_permalink(); ?>"><?php the_title(); ?></a></h3>
          <div class="readmore-btn">
                 <a href="<?php the_permalink(); ?>">Read More</a>
             </div>
        </div>
        </div>
         
        <?php endwhile;
            wp_reset_postdata(); 
        endif;
        ?>
    </div>
    <div class="hm-blog-btn"><a href="<?php echo esc_url(home_url('/blog/')); ?>" class="cmn-btn">View all Blog posts</a></div>
